import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { Module, Lesson, Quiz, Question } from '../../../core/models';

@Component({
  selector: 'app-course-editor',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './course-editor.component.html',
  styleUrl: './course-editor.component.css',
})
export class CourseEditorComponent {
  loading = signal(false);
  error = signal<string | null>(null);

  courseId = 'c1';
  courseTitle = signal('Intro to Web Development');
  courseDescription = signal('HTML, CSS, and JavaScript fundamentals.');

  modules = signal<Module[]>([
    {
      id: 'm1',
      courseId: 'c1',
      order: 1,
      title: 'Getting Started with HTML',
      lessons: [
        { id: 'l1', moduleId: 'm1', order: 1, title: 'What is HTML?', content: 'HTML is the structure of the web.' },
        { id: 'l2', moduleId: 'm1', order: 2, title: 'Structure of a Page', content: 'Head and body sections.' },
      ],
      quizzes: [
        {
          id: 'q1',
          moduleId: 'm1',
          title: 'HTML Basics Quiz',
          attemptLimit: 2,
          questions: [
            { id: 'qq1', quizId: 'q1', text: 'What does HTML stand for?', options: ['HyperText Markup Language', 'Hot Mail', 'How To Make Lists'], correctIdx: 0 },
            { id: 'qq2', quizId: 'q1', text: 'Which tag defines a paragraph?', options: ['<p>', '<par>', '<text>'], correctIdx: 0 },
          ],
        },
      ],
    },
    {
      id: 'm2',
      courseId: 'c1',
      order: 2,
      title: 'Styling with CSS',
      lessons: [
        { id: 'l3', moduleId: 'm2', order: 1, title: 'Selectors & the Box Model', content: 'How CSS targets elements.' },
      ],
      quizzes: [],
    },
  ]);

  newModuleTitle = '';

  addModule(): void {
    const title = this.newModuleTitle.trim();
    if (!title) return;
    const order = this.modules().length + 1;
    this.modules.update((m) => [
      ...m,
      { id: 'm-new-' + order, courseId: this.courseId, order, title, lessons: [], quizzes: [] },
    ]);
    this.newModuleTitle = '';
  }

  removeModule(mod: Module): void {
    this.modules.update((m) => m.filter((x) => x.id !== mod.id));
  }

  moveModule(mod: Module, dir: -1 | 1): void {
    this.modules.update((list) => {
      const arr = [...list];
      const i = arr.findIndex((x) => x.id === mod.id);
      const j = i + dir;
      if (i < 0 || j < 0 || j >= arr.length) return list;
      [arr[i], arr[j]] = [arr[j], arr[i]];
      return arr.map((x, idx) => ({ ...x, order: idx + 1 }));
    });
  }

  // ---- Lessons ----
  addLesson(mod: Module, title: string, content: string, form: HTMLFormElement): void {
    if (!title.trim()) return;
    const lesson: Lesson = {
      id: `${mod.id}-l-${mod.lessons.length + 1}-${title.length}`,
      moduleId: mod.id,
      order: mod.lessons.length + 1,
      title: title.trim(),
      content: content.trim(),
    };
    this.updateModule(mod.id, (m) => ({ ...m, lessons: [...m.lessons, lesson] }));
    form.reset();
  }

  removeLesson(mod: Module, lesson: Lesson): void {
    this.updateModule(mod.id, (m) => ({ ...m, lessons: m.lessons.filter((l) => l.id !== lesson.id) }));
  }

  // ---- Quizzes ----
  addQuiz(mod: Module, title: string, limit: string, form: HTMLFormElement): void {
    if (!title.trim()) return;
    const quiz: Quiz = {
      id: 'q-new-' + mod.quizzes.length,
      moduleId: mod.id,
      title: title.trim(),
      attemptLimit: Math.max(1, parseInt(limit, 10) || 1),
      questions: [],
    };
    this.updateModule(mod.id, (m) => ({ ...m, quizzes: [...m.quizzes, quiz] }));
    form.reset();
  }

  removeQuiz(mod: Module, quiz: Quiz): void {
    this.updateModule(mod.id, (m) => ({ ...m, quizzes: m.quizzes.filter((q) => q.id !== quiz.id) }));
  }

  addQuestion(mod: Module, quiz: Quiz, text: string, opts: string, correct: string, form: HTMLFormElement): void {
    const options = opts.split('\n').map((o) => o.trim()).filter(Boolean);
    if (!text.trim() || options.length < 2) return;
    const correctIdx = Math.min(Math.max(0, parseInt(correct, 10) - 1 || 0), options.length - 1);
    const question: Question = {
      id: 'qq-new-' + (quiz.questions?.length ?? 0),
      quizId: quiz.id,
      text: text.trim(),
      options,
      correctIdx,
    };
    this.updateModule(mod.id, (m) => ({
      ...m,
      quizzes: m.quizzes.map((q) =>
        q.id === quiz.id ? { ...q, questions: [...(q.questions ?? []), question] } : q,
      ),
    }));
    form.reset();
  }

  private updateModule(id: string, fn: (m: Module) => Module): void {
    this.modules.update((list) => list.map((m) => (m.id === id ? fn(m) : m)));
  }
}
